      await new Promise((resolve2, reject) => {
        transaction.oncomplete = () => resolve2();
        transaction.onerror = () => reject(transaction.error);
      });
      db.close();
      console.log(`\u2705 Sequential vector ID generated: ${nextId} (from counter DB)`);
      return nextId;
