function validateConfig(config2) {
  const errors = [];
  if (!config2.apiUrl) {
    errors.push("apiUrl is required");
  }
  if (!config2.packageId || config2.packageId === "0x0") {
    console.warn("PDW SDK: packageId not configured. Please set a valid deployed package ID.");
  }
  if (config2.apiUrl && !isValidUrl(config2.apiUrl)) {
    errors.push("apiUrl must be a valid HTTP or HTTPS URL");
  }
  if (config2.encryptionConfig?.enabled && (!config2.encryptionConfig.keyServers || config2.encryptionConfig.keyServers.length === 0)) {
    console.warn("PDW SDK: Encryption is enabled but no key servers configured. Some features may not work.");
  }
  if (config2.encryptionConfig?.policyConfig?.threshold) {
    const threshold = config2.encryptionConfig.policyConfig.threshold;
    if (threshold < 1) {
      errors.push("Encryption threshold must be at least 1");
    }
  }
  if (config2.storageConfig?.provider && !["walrus", "local"].includes(config2.storageConfig.provider)) {
    errors.push('Storage provider must be either "walrus" or "local"');
  }
  if (errors.length > 0) {
    throw new ConfigurationError(errors.join("; "));
  }
  return config2;
}
