// src/client/namespaces/EmbeddingsNamespace.ts
var EmbeddingsNamespace = class {
  constructor(services) {
    this.services = services;
  }
  /**
   * Generate embedding for single text
   *
   * Delegates to: EmbeddingService.embedText()
   *
   * @param text - Text to embed
   * @param options - Embedding options
   * @returns Embedding vector (768 dimensions for Gemini)
   */
  async generate(text2, options) {
    if (!this.services.embedding) {
      throw new Error("Embedding service not configured. Please provide geminiApiKey.");
    }
    const result = await this.services.embedding.embedText({ text: text2 });
    return result.vector;
  }
  /**
   * Generate embeddings for multiple texts
   *
   * Delegates to: EmbeddingService.embedBatch()
   *
   * @param texts - Array of texts
   * @returns Array of embedding vectors
   */
  async batch(texts) {
    if (!this.services.embedding) {
      throw new Error("Embedding service not configured.");
    }
    const result = await this.services.embedding.embedBatch(texts);
    return result.vectors;
  }
  /**
   * Calculate cosine similarity between two vectors
   *
   * Delegates to: EmbeddingService.calculateCosineSimilarity()
   *
   * @param vector1 - First vector
   * @param vector2 - Second vector
   * @returns Similarity score (0-1, higher is more similar)
   */
  similarity(vector1, vector2) {
    if (!this.services.embedding) {
      throw new Error("Embedding service not configured.");
    }
    return this.services.embedding.calculateCosineSimilarity(vector1, vector2);
  }
  /**
   * Find most similar vectors from candidates
   *
   * Delegates to: EmbeddingService.findMostSimilar()
   *
   * @param queryVector - Query vector
   * @param candidateVectors - Candidate vectors to compare
   * @param k - Number of results (default: 5)
   * @returns Top k similar vectors with scores
   */
  findSimilar(queryVector, candidateVectors, k = 5) {
    if (!this.services.embedding) {
      throw new Error("Embedding service not configured.");
    }
    const results = this.services.embedding.findMostSimilar(queryVector, candidateVectors, k);
    return results.map((r) => ({
      index: r.index,
      score: r.similarity
    }));
  }
};

// src/client/namespaces/ChatNamespace.ts
var ChatNamespace = class {
  constructor(services) {
    this.services = services;
  }
  /**
   * Create a new chat session
   *
   * Delegates to: ChatService.createSession()
   *
   * @param options - Session options
   * @returns Created session
   */
  async createSession(options) {
    const result = await this.services.chat.createSession({
      userAddress: this.services.config.userAddress,
      modelName: options?.model || "gemini-2.5-flash",
      title: options?.title || "New Chat"
    });
    return result.session;
  }
  /**
   * Get chat session
   *
   * Delegates to: ChatService.getSession()
   *
   * @param sessionId - Session ID
   * @returns Session with messages
   */
  async getSession(sessionId) {
    const result = await this.services.chat.getSession(
      sessionId,
      this.services.config.userAddress
    );
    return result.session;
  }
  /**
   * Get all user sessions
   *
   * Delegates to: ChatService.getSessions()
   *
   * @returns Array of sessions
   */
  async getSessions() {
    const result = await this.services.chat.getSessions(
      this.services.config.userAddress
    );
    return result.sessions;
  }
  /**
   * Send message (non-streaming)
   *
   * Delegates to: ChatService.sendMessage()
   *
   * @param sessionId - Session ID
   * @param message - Message text
   * @returns AI response
   */
  async send(sessionId, message) {
    const result = await this.services.chat.sendMessage({
      text: message,
      userId: this.services.config.userAddress,
      userAddress: this.services.config.userAddress,
      sessionId
    });
    return {
      role: "assistant",
      // ChatService returns response message
      content: result.content || "",
      timestamp: Date.now()
    };
  }
  /**
   * Stream chat response
   *
   * Delegates to: ChatService.streamChat()
   *
   * @param sessionId - Session ID
   * @param message - Message text
   * @param callbacks - Streaming callbacks
   */
  async stream(sessionId, message, callbacks) {
    await this.services.chat.streamChat(
      {
        text: message,
        userId: this.services.config.userAddress,
        userAddress: this.services.config.userAddress,
        sessionId
      },
      {
        onMessage: callbacks.onMessage || (() => {
        }),
        onDone: callbacks.onDone || (() => {
        }),
        onError: callbacks.onError ? (event) => callbacks.onError(new Error(event.data)) : void 0
      }
    );
  }
  /**
   * Update session title
   *
   * Delegates to: ChatService.updateSessionTitle()
   *
   * @param sessionId - Session ID
   * @param title - New title
   */
  async updateTitle(sessionId, title) {
    await this.services.chat.updateSessionTitle(
      sessionId,
      this.services.config.userAddress,
      title
    );
  }
  /**
   * Delete chat session
   *
   * Delegates to: ChatService.deleteSession()
   *
   * @param sessionId - Session ID
   */
  async delete(sessionId) {
    await this.services.chat.deleteSession(
      sessionId,
      this.services.config.userAddress
    );
  }
};

// src/client/namespaces/BatchNamespace.ts
var BatchNamespace = class {
  constructor(services) {
    this.services = services;
  }
  /**
   * Create many memories in batch
   *
   * Delegates to: MemoryNamespace.createBatch()
   *
   * @param contents - Array of content strings
   * @param options - Optional creation options
   * @returns Array of created memory objects
   */
  async createMany(contents, options) {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    const { MemoryNamespace: MemoryNamespace2 } = await Promise.resolve().then(() => (init_MemoryNamespace(), MemoryNamespace_exports));
    const memoryNamespace = new MemoryNamespace2(this.services);
    const memories = await memoryNamespace.createBatch(
      contents,
      {
        category: options?.category,
        importance: options?.importance
      }
    );
    return memories.map((m) => ({
      id: m.id,
      blobId: m.blobId
    }));
  }
  /**
   * Update many memories in batch
   *
   * Updates memories in parallel:
   * 1. For updates with new content: uploads new blobs to Walrus
   * 2. Executes on-chain update transactions
   * 3. Updates local vector index if enabled
   *
   * @param updates - Array of {id, content, category, importance, topic}
   * @returns Array of successfully updated memory IDs
   */
  async updateMany(updates) {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    if (!this.services.tx) {
      throw new Error("Transaction service not configured.");
    }
    const successfulIds = [];
    const errors = [];
    const BATCH_SIZE = 5;
    for (let i = 0; i < updates.length; i += BATCH_SIZE) {
      const batch = updates.slice(i, i + BATCH_SIZE);
      const batchPromises = batch.map(async (update) => {
        try {
          let newBlobId = "";
          let newContentHash = "";
          let newContentSize = 0;
          if (update.content) {
            let embedding = [];
            if (this.services.embedding) {
              const embResult = await this.services.embedding.embedText({
                text: update.content
              });
              embedding = embResult.vector;
            }
            const uploadResult = await this.services.storage.uploadMemoryPackage(
              {
                content: update.content,
                embedding,
                metadata: {
                  category: update.category || "general",
                  importance: update.importance || 5,
                  topic: update.topic || ""
                },
                identity: this.services.config.userAddress
              },
              {
                signer: this.services.config.signer.getSigner(),
                epochs: 3,
                deletable: true
              }
            );
            newBlobId = uploadResult.blobId;
            newContentHash = uploadResult.blobId;
            newContentSize = update.content.length;
          }
          const tx = this.services.tx.buildUpdateMemoryRecord({
            memoryId: update.id,
            newBlobId,
            newCategory: update.category || "",
            newTopic: update.topic || "",
            newImportance: update.importance || 0,
            newEmbeddingBlobId: "",
            newContentHash,
            newContentSize
          });
          const result = await this.services.tx.executeTransaction(
            tx,
            this.services.config.signer.getSigner()
          );
          if (result.status !== "success") {
            throw new Error(result.error || "Transaction failed");
          }
          if (update.content && this.services.vector && this.services.embedding) {
            const embResult = await this.services.embedding.embedText({
              text: update.content
            });
            await this.services.vector.addVector(
              this.services.config.userAddress,
              Date.now(),
              // vectorId
              embResult.vector,
              {
                category: update.category,
                importance: update.importance,
                topic: update.topic
              }
            );
          }
          return { success: true, id: update.id };
        } catch (error40) {
          const errorMsg = error40 instanceof Error ? error40.message : String(error40);
          console.warn(`Failed to update memory ${update.id}:`, errorMsg);
          return { success: false, id: update.id, error: errorMsg };
        }
      });
      const batchResults = await Promise.all(batchPromises);
      for (const result of batchResults) {
        if (result.success) {
          successfulIds.push(result.id);
        } else {
          errors.push({ id: result.id, error: result.error || "Unknown error" });
        }
      }
    }
    if (errors.length > 0) {
      console.warn(`Batch update completed with ${errors.length} errors:`, errors);
    }
    return successfulIds;
  }
  /**
   * Delete many memories in batch
   *
   * Delegates to: MemoryService.deleteMemoryRecord() for each
   *
   * @param ids - Array of memory IDs
   * @returns Number of successfully deleted
   */
  async deleteMany(ids) {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    let successCount = 0;
    for (const id of ids) {
      try {
        await this.services.memory.deleteMemoryRecord(
          id,
          this.services.config.userAddress,
          this.services.config.signer.getSigner()
        );
        successCount++;
      } catch (error40) {
        console.warn(`Failed to delete memory ${id}:`, error40);
      }
    }
    return successCount;
  }
  /**
   * Upload many files in batch
   *
   * Delegates to: StorageService.uploadMemoryBatch()
   *
   * @param files - Array of {name, data}
   * @returns Quilt result with blob IDs
   */
  async uploadMany(files) {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    const memories = files.map((f2) => ({
      content: new TextDecoder().decode(f2.data),
      category: "file",
      importance: 5,
      topic: f2.name,
      embedding: [],
      encryptedContent: f2.data,
      summary: ""
    }));
    const result = await this.services.storage.uploadMemoryBatch(
      memories,
      {
        signer: this.services.config.signer.getSigner(),
        epochs: 3,
        userAddress: this.services.config.userAddress
      }
    );
    return {
      quiltId: result.quiltId,
      files: result.files.map((f2) => ({
        name: f2.identifier,
        blobId: f2.blobId
      }))
    };
  }
  /**
   * Get batch processing progress
   *
   * Delegates to: BatchService.getStats()
   *
   * @returns Current batch progress
   */
  getProgress() {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    const stats = this.services.batchService.getStats();
    let total = 0;
    let completed = 0;
    let failed = 0;
    for (const [, stat] of stats) {
      total += stat.totalItems;
      completed += stat.successCount;
      failed += stat.errorCount;
    }
    const percentage = total > 0 ? completed / total * 100 : 0;
    return {
      total,
      completed,
      failed,
      inProgress: total - completed - failed,
      percentage
    };
  }
  /**
   * Get batch statistics
   *
   * Delegates to: BatchService.getStats()
   *
   * @param type - Optional batch type ('memory-create', 'storage', etc.)
   * @returns Batch statistics
   */
  getStats(type) {
    if (!this.services.batchService) {
      throw new Error("Batch service not configured.");
    }
    const stats = this.services.batchService.getStats(type);
    if (stats instanceof Map) {
      return stats;
    }
    return stats;
  }
};

